def composition_score(layer_a, head_a, layer_b, head_b, comp_type="Q"):
    W_O_a = model.W_O[layer_a, head_a]  # [d_head, d_model]
    if comp_type == "Q":
        W_in_b = model.W_Q[layer_b, head_b]
    elif comp_type == "K":
        W_in_b = model.W_K[layer_b, head_b]
    else:
        W_in_b = model.W_V[layer_b, head_b]
    comp_matrix = W_O_a @ W_in_b  # [d_head, d_head]
    return comp_matrix.norm().item()
